create_files.content:
pipeline {
  agent any
  environment {
    AWS_DEFAULT_REGION = 'us-east-1'
    NPM_TOKEN = credentials('npm-publish-token')
  }
  stages {
    stage('Test') {
      steps {
        sh 'npm test'
      }
    }
    stage('Build') {
      steps {
        sh 'npm run build'
      }
    }
    stage('Deploy') {
      steps {
        sh './diagnostic.sh'
        sh 'aws s3 sync dist/ s3://myapp-deploy/'
      }
    }
  }
}
